const update = $input.first().json.body || $input.first().json;

const message = update.message || update.edited_message;
const callbackQuery = update.callback_query;

if (callbackQuery) {
  return [{
    json: {
      update_type: 'callback_query',
      update_id: update.update_id,
      callback_query_id: callbackQuery.id,
      chat_id: callbackQuery.message.chat.id,
      message_id: callbackQuery.message.message_id,
      user_id: callbackQuery.from.id,
      username: callbackQuery.from.username || '',
      first_name: callbackQuery.from.first_name || '',
      callback_data: callbackQuery.data || ''
    }
  }];
}

if (message) {
  const text = (message.text || '').trim();
  const isCommand = text.startsWith('/');
  let command = null;
  let args = '';

  if (isCommand) {
    const parts = text.split(' ');
    command = parts[0].toLowerCase().split('@')[0];
    args = parts.slice(1).join(' ').trim();
  }

  return [{
    json: {
      update_type: 'message',
      update_id: update.update_id,
      chat_id: message.chat.id,
      message_id: message.message_id,
      user_id: message.from.id,
      username: message.from.username || '',
      first_name: message.from.first_name || '',
      text,
      is_command: isCommand,
      command,
      args
    }
  }];
}

return [{ json: { update_type: 'unknown', chat_id: 0 } }];

const update = $input.first().json;
if (update.update_type === 'unknown') {
  return [{ json: { ...update, auth_failed: true, auth_reason: 'unknown_update_type' } }];
}

const allowed = ($env.TELEGRAM_ALLOWED_USERS || '')
  .split(',')
  .map(s => parseInt(s.trim()))
  .filter(Boolean);

const isAllowed = allowed.length === 0 || allowed.includes(update.chat_id);
return [{ json: { ...update, auth_failed: !isAllowed } }];

const convRows = $input.first().json;
const conv = Array.isArray(convRows) ? convRows[0] : convRows;
const update = $('Check Authorization').first().json;

return [{
  json: {
    ...update,
    conv_state: conv.state || 'idle',
    conv_project_id: conv.project_id || null,
    conv_context: conv.context || {},
    conv_id: conv.id
  }
}];

// Parse callback_data format: {action}:{approval_type}:{entity_id}:{chat_id}:{timestamp}
const d = $input.first().json;
const parts = (d.callback_data || '').split(':');
const action = parts[0]; // approve | reject | postpone
const approvalType = parts[1] || '';
const entityId = parts[2] || '';
const callbackBase = parts.slice(1).join(':'); // everything after action

const statusMap = { approve: 'approved', reject: 'rejected', postpone: 'postponed' };
const newStatus = statusMap[action] || 'rejected';

const emojiMap = { approved: '✅', rejected: '❌', postponed: '⏸' };
const labelMap = {
  approved: 'Aprobado',
  rejected: 'Rechazado',
  postponed: 'Pospuesto'
};
const typeLabels = {
  deploy: 'Deployment',
  start_development: 'Inicio de desarrollo',
  structural_change: 'Cambio estructural',
  improvement: 'Mejora',
  data_deletion: 'Eliminación de datos',
  refactor: 'Refactorización'
};

const confirmMsg = `${emojiMap[newStatus]} *${labelMap[newStatus]}*\n\n_${typeLabels[approvalType] || approvalType}_ ha sido ${labelMap[newStatus].toLowerCase()}.`;

return [{
  json: {
    ...d,
    action,
    approval_type: approvalType,
    entity_id: entityId,
    callback_base: callbackBase,
    new_status: newStatus,
    confirm_message: confirmMsg,
    should_execute: action === 'approve'
  }
}];

const cb = $('Handle Approval Callback').first().json;
// Trigger the appropriate workflow based on approval_type via n8n webhook/API
// For deploy: trigger workflow 06 via HTTP call to its executeWorkflow endpoint
// For start_development: trigger workflow 02
// For improvement: trigger workflow 10
const typeToWebhook = {
  start_development: `${$env.N8N_WEBHOOK_URL}webhook/project-setup`,
  deploy: `${$env.N8N_WEBHOOK_URL}webhook/deploy-trigger`,
  improvement: `${$env.N8N_WEBHOOK_URL}webhook/improvement-trigger`
};
const webhookUrl = typeToWebhook[cb.approval_type];
return [{ json: { ...cb, trigger_url: webhookUrl, entity_id: cb.entity_id } }];

const projects = $input.first().json;
const update = $('Merge Conversation State').first().json;
const firstName = update.first_name || 'usuario';

const statusEmoji = {
  intake: '📥', setup: '⚙️', agent_pipeline: '🤖', code_generation: '💻',
  validation: '🔍', deploying: '🚀', qa: '🧪', live: '✅',
  improving: '🔄', failed: '❌', archived: '📦'
};

let projectList = '';
if (Array.isArray(projects) && projects.length > 0) {
  projectList = projects.map((p, i) =>
    `${i + 1}\. ${statusEmoji[p.status] || '▫️'} *${p.name}* — _${p.status}_`
  ).join('\n');
} else {
  projectList = '_No hay proyectos activos aún._';
}

const msg = `🏭 *Software Factory Autónoma*\n\nHola, ${firstName}\! Soy tu fábrica de software con IA\.\n\n*Proyectos activos:*\n${projectList}\n\n*Comandos disponibles:*\n/nuevo — Crear proyecto\n/estado — Estado del proyecto\n/roadmap — Ver roadmap\n/deploy — Desplegar\n/qa — Ejecutar pruebas\n/errores — Ver errores\n/mejorar — Solicitar mejora\n/feedback — Enviar feedback\n/costos — Ver consumo\n/agentes — Actividad de agentes`;

return [{ json: { ...update, response_text: msg } }];

const projects = $input.first().json;
const update = $('Merge Conversation State').first().json;

if (!Array.isArray(projects) || projects.length === 0) {
  const noArgs = !update.args;
  return [{ json: { ...update, response_text: noArgs
    ? '❓ *¿De qué proyecto?*\n\nUsa: `/estado nombre\-del\-proyecto`'
    : `❌ No encontré el proyecto *${update.args}*\. Verifica el nombre\.` } }];
}

const p = projects[0];
const statusEmoji = {
  intake: '📥', setup: '⚙️', agent_pipeline: '🤖', code_generation: '💻',
  validation: '🔍', deploying: '🚀', qa: '🧪', live: '✅ Live',
  improving: '🔄', failed: '❌', archived: '📦'
};

const lastUpdate = new Date(p.updated_at);
const diffMs = Date.now() - lastUpdate.getTime();
const diffHours = Math.round(diffMs / 3600000);
const timeAgo = diffHours < 1 ? 'hace menos de 1 hora' : diffHours < 24 ? `hace ${diffHours}h` : `hace ${Math.round(diffHours/24)}d`;

const deployLine = p.vercel_deployment_url
  ? `\n🌐 URL: ${p.vercel_deployment_url}`
  : '';
const githubLine = p.github_repo_url
  ? `\n📂 GitHub: ${p.github_repo_url}`
  : '';

const msg = `📊 *${p.name}*\n\n🔘 Estado: *${statusEmoji[p.status] || p.status}*\n🔄 Iteración: ${p.current_iteration}\n🕐 Última actividad: _${timeAgo}_${githubLine}${deployLine}`;

return [{ json: { ...update, response_text: msg } }];

const reqs = $input.first().json;
const update = $('Merge Conversation State').first().json;

if (!Array.isArray(reqs) || reqs.length === 0) {
  return [{ json: { ...update, response_text: '❌ No se encontró roadmap\. Primero crea un proyecto con /nuevo y espera a que se genere el PRD\.' } }];
}

const r = reqs[0];
const roadmap = Array.isArray(r.roadmap) ? r.roadmap : [];
const objectives = Array.isArray(r.objectives) ? r.objectives : [];

let roadmapText = roadmap.slice(0, 8).map((item, i) => {
  const label = typeof item === 'string' ? item : (item.milestone || item.title || JSON.stringify(item));
  const week = item.week || item.sprint || '';
  const prefix = week ? `📍 _${week}_: ` : `${i + 1}\. `;
  return `${prefix}${label}`;
}).join('\n');

if (!roadmapText) roadmapText = '_Roadmap no disponible aún_';

const stack = r.tech_stack || {};
const stackText = Object.values(stack).filter(Boolean).slice(0, 5).join(' · ') || 'React \+ Vite \+ Supabase';

const msg = `🗺 *Roadmap del Proyecto*\n\n📦 Stack: ${stackText}\n\n*Hitos:*\n${roadmapText}`;

return [{ json: { ...update, response_text: msg } }];

const projects = $input.first().json;
const update = $('Merge Conversation State').first().json;

if (!Array.isArray(projects) || projects.length === 0) {
  return [{ json: { ...update, response_text: '❌ No hay proyectos listos para deploy\.', skip_approval: true } }];
}

const p = projects[0];
// Build approval callback_data
const callbackBase = `deploy:${p.id}:${update.chat_id}:${Date.now()}`;

const msg = `🚀 *Deploy a Producción*\n\n📦 Proyecto: *${p.name}*\n🔘 Estado actual: _${p.status}_\n\n¿Confirmas el despliegue a Vercel?`;
const keyboard = {
  inline_keyboard: [
    [
      { text: '✅ APROBAR', callback_data: `approve:${callbackBase}` },
      { text: '❌ RECHAZAR', callback_data: `reject:${callbackBase}` },
      { text: '⏸ POSPONER', callback_data: `postpone:${callbackBase}` }
    ]
  ]
};

return [{ json: { ...update, response_text: msg, reply_markup: keyboard, project_id: p.id, callback_base: callbackBase, skip_approval: false } }];

const update = $('Merge Conversation State').first().json;
const projectId = update.conv_project_id || update.args;

if (!projectId) {
  return [{ json: { ...update, response_text: '🧪 *QA Manual*\n\nEspecifica el proyecto: `/qa nombre\-del\-proyecto`' } }];
}

return [{
  json: {
    ...update,
    response_text: `🧪 *Ejecutando QA*\n\nIniciando suite de pruebas Playwright\.\.\. Recibirás los resultados en unos minutos\.`,
    trigger_payload: { project_id: projectId, source: 'telegram_command', chat_id: update.chat_id }
  }
}];

const errors = $input.first().json;
const update = $('Merge Conversation State').first().json;

if (!Array.isArray(errors) || errors.length === 0) {
  return [{ json: { ...update, response_text: '✅ No hay errores de QA pendientes\.' } }];
}

const errorLines = errors.map((e, i) =>
  `${i + 1}\. *${e.test_name}*\n   Suite: ${e.test_suite}\n   Error: _${(e.error_message || 'unknown').slice(0, 80)}_`
).join('\n\n');

const msg = `🐛 *Errores Recientes \(${errors.length}\)*\n\n${errorLines}`;
return [{ json: { ...update, response_text: msg } }];

const rows = $input.first().json;
const update = $('Merge Conversation State').first().json;

if (!Array.isArray(rows) || rows.length === 0) {
  return [{ json: { ...update, response_text: '📊 No hay datos de consumo aún\.' } }];
}

// Aggregate by agent_role
const byRole = {};
let totalTokens = 0;
for (const r of rows) {
  const role = r.agent_role || 'unknown';
  byRole[role] = (byRole[role] || 0) + (r.token_count || 0);
  totalTokens += (r.token_count || 0);
}

const PRICE_PER_1K = 0.000075; // gemini-2.0-flash approx
const totalCost = (totalTokens / 1000) * PRICE_PER_1K;

const roleLines = Object.entries(byRole)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 8)
  .map(([role, tokens]) => `  • ${role}: ${tokens.toLocaleString()} tokens`)
  .join('\n');

const msg = `💰 *Consumo de Recursos*\n\n🔢 Total tokens: *${totalTokens.toLocaleString()}*\n💵 Costo estimado: *$${totalCost.toFixed(4)} USD*\n\n*Por agente:*\n${roleLines}\n\n_Modelo: gemini\-2\.0\-flash\-exp_`;

return [{ json: { ...update, response_text: msg } }];

const rows = $input.first().json;
const update = $('Merge Conversation State').first().json;

if (!Array.isArray(rows) || rows.length === 0) {
  return [{ json: { ...update, response_text: '🤖 No hay actividad de agentes aún\.' } }];
}

const agentEmoji = {
  product_manager: '📋', architect: '🏛', ux_ui_designer: '🎨',
  backend_engineer: '⚙️', frontend_engineer: '💻', database_engineer: '🗄',
  qa_engineer: '🧪', devops_engineer: '🚢', security_auditor: '🔒'
};

const lines = rows.slice(0, 8).map(r => {
  const emoji = agentEmoji[r.agent_role] || '🤖';
  const time = new Date(r.created_at).toLocaleTimeString('es', { hour: '2-digit', minute: '2-digit' });
  const latency = r.latency_ms ? ` \(${Math.round(r.latency_ms / 1000)}s\)` : '';
  return `${emoji} *${r.agent_role.replace(/_/g, '\\_')}* — ${r.token_count || 0} tokens${latency} — ${time}`;
}).join('\n');

const msg = `🤖 *Actividad Reciente de Agentes*\n\n${lines}`;
return [{ json: { ...update, response_text: msg } }];

// Free text handler — routes based on conversation state
const update = $input.first().json;
const state = update.conv_state || 'idle';
const text = update.text || '';

if (state === 'awaiting_idea') {
  return [{ json: { ...update, free_text_route: 'create_project', idea: text } }];
}
if (state === 'awaiting_improvement') {
  return [{ json: { ...update, free_text_route: 'improvement', improvement_text: text } }];
}
if (state === 'awaiting_feedback_text') {
  return [{ json: { ...update, free_text_route: 'feedback', feedback_text: text } }];
}

// idle state: treat as a new idea if it's long enough
if (text.length >= 20) {
  return [{ json: { ...update, free_text_route: 'create_project', idea: text } }];
}

return [{ json: { ...update, free_text_route: 'help' } }];
